import java.util.TreeSet

fun solve(s: String, order: Array<Long>, k: Long): Long {
    val n = s.length
    val totalSubstrings = n * (n + 1) / 2L
    val stars = TreeSet<Int>()
    var nonStarCount = totalSubstrings

    for (t in 0 until n) {
        val x = order[t].toInt()
        val left = stars.floor(x) ?: -1
        val right = stars.ceil(x) ?: n
        val length = right - left - 1
        val contribution = (length * (length + 1)) / 2
        nonStarCount -= contribution

        val leftSegmentStart = left + 1
        val leftSegmentEnd = x - 1
        if (leftSegmentStart <= leftSegmentEnd) {
            val contribLeft = (leftSegmentEnd - leftSegmentStart + 1) * (leftSegmentEnd - leftSegmentStart + 2) / 2
            nonStarCount += contribLeft
        }

        val rightSegmentStart = x + 1
        val rightSegmentEnd = right - 1
        if (rightSegmentStart <= rightSegmentEnd) {
            val contribRight = (rightSegmentEnd - rightSegmentStart + 1) * (rightSegmentEnd - rightSegmentStart + 2) / 2
            nonStarCount += contribRight
        }

        stars.add(x)
        val currentValid = totalSubstrings - nonStarCount
        if (currentValid >= k) {
            return t.toLong()
        }
    }

    return -1L
}
